from dataclasses import dataclass, field
from typing import Any


@dataclass
class Node:
    line: int = field(default=0, compare=False, repr=False)


# ── Top-level ────────────────────────────────────────────────────────────────

@dataclass
class ProgramNode(Node):
    version: int
    left_to_right: str          # "true" | "false" | "arbitrary"
    body: list["Node"]


# ── Literals ─────────────────────────────────────────────────────────────────

@dataclass
class NumberNode(Node):
    value: int | float


@dataclass
class StringNode(Node):
    value: str


@dataclass
class BoolNode(Node):
    value: bool


@dataclass
class IdentifierNode(Node):
    name: str


@dataclass
class ArrayNode(Node):
    elements: list["Node"]


# ── Grouping ──────────────────────────────────────────────────────────────────

@dataclass
class GroupSingleNode(Node):
    """{ expr } — single-value grouping"""
    expr: "Node"


@dataclass
class GroupMultiNode(Node):
    """| a b c | — multi-value grouping"""
    items: list["Node"]


# ── Assignment ────────────────────────────────────────────────────────────────

@dataclass
class AssignNode(Node):
    """
    Represents an assignment. target is always the variable name.
    Direction (which token was left vs right) is resolved by the parser
    according to the left-to-right header flag.
    """
    target: str
    value: "Node"


# ── Directives ────────────────────────────────────────────────────────────────

@dataclass
class DirectiveNode(Node):
    """
    @name arg1 arg2 ...
    args are themselves Nodes (identifiers, literals, nested directives, groups).
    """
    name: str
    args: list["Node"]


# ── Block declaration ─────────────────────────────────────────────────────────

@dataclass
class BlockDeclNode(Node):
    """
    @decl name:
    --statement
    --statement
    """
    block_name: str
    body: list["Node"]

"""
CFML Lexer — turns raw source text into a flat list of Tokens.
"""

from __future__ import annotations
from dataclasses import dataclass
from enum import Enum, auto


class TT(Enum):
    """Token types."""
    # Literals
    NUMBER      = auto()
    STRING      = auto()
    BOOL        = auto()
    # Names / directives
    IDENTIFIER  = auto()
    DIRECTIVE   = auto()   # @word
    # Structural
    LBRACKET    = auto()   # [
    RBRACKET    = auto()   # ]
    LBRACE      = auto()   # {
    RBRACE      = auto()   # }
    PIPE        = auto()   # |
    COMMA       = auto()   # ,
    COLON       = auto()   # :
    INDENT      = auto()   # -- prefix (block body marker)
    NEWLINE     = auto()
    EOF         = auto()


@dataclass
class Token:
    type: TT
    value: object          # str | int | float | bool | None
    line: int

    def __repr__(self) -> str:
        return f"Token({self.type.name}, {self.value!r}, line={self.line})"


class LexError(Exception):
    def __init__(self, msg: str, line: int):
        super().__init__(f"[line {line}] LexError: {msg}")
        self.line = line


class Lexer:
    def __init__(self, source: str):
        self.src = source
        self.pos = 0
        self.line = 1
        self.tokens: list[Token] = []

    # ── Public entry point ────────────────────────────────────────────────────

    def tokenize(self) -> list[Token]:
        while self.pos < len(self.src):
            self._scan_token()
        self.tokens.append(Token(TT.EOF, None, self.line))
        return self.tokens

    # ── Internal helpers ──────────────────────────────────────────────────────

    def _peek(self, offset: int = 0) -> str | None:
        idx = self.pos + offset
        return self.src[idx] if idx < len(self.src) else None

    def _advance(self) -> str:
        ch = self.src[self.pos]
        self.pos += 1
        if ch == "\n":
            self.line += 1
        return ch

    def _add(self, tt: TT, value: object = None) -> None:
        self.tokens.append(Token(tt, value, self.line))

    def _skip_line_comment(self) -> None:
        while self.pos < len(self.src) and self.src[self.pos] != "\n":
            self.pos += 1

    def _read_string(self) -> str:
        self._advance()  # opening "
        buf: list[str] = []
        while True:
            ch = self._peek()
            if ch is None:
                raise LexError("unterminated string literal", self.line)
            if ch == "\n":
                raise LexError("newline inside string literal", self.line)
            self._advance()
            if ch == '"':
                break
            if ch == "\\":
                esc = self._peek()
                if esc is None:
                    raise LexError("unterminated escape sequence", self.line)
                self._advance()
                buf.append({"n": "\n", "t": "\t", "\\": "\\", '"': '"'}.get(esc, esc))
            else:
                buf.append(ch)
        return "".join(buf)

    def _read_number(self) -> int | float:
        start = self.pos
        while self._peek() and (self._peek().isdigit() or self._peek() == "."):
            self._advance()
        raw = self.src[start:self.pos]
        return float(raw) if "." in raw else int(raw)

    def _read_word(self) -> str:
        start = self.pos
        while self._peek() and (self._peek().isalnum() or self._peek() in "_-"):
            self._advance()
        return self.src[start:self.pos]

    # ── Main scan ─────────────────────────────────────────────────────────────

    def _scan_token(self) -> None:
        ch = self._peek()

        # Whitespace (non-newline)
        if ch in (" ", "\t", "\r"):
            self._advance()
            return

        # Newlines
        if ch == "\n":
            self._advance()
            # Suppress consecutive newlines — one is enough
            if self.tokens and self.tokens[-1].type != TT.NEWLINE:
                self._add(TT.NEWLINE)
            return

        # Line comments  # ...
        if ch == "#":
            self._skip_line_comment()
            return

        # Block-body indent marker  --
        if ch == "-" and self._peek(1) == "-":
            self.pos += 2
            self._add(TT.INDENT)
            return

        # String literals
        if ch == '"':
            s = self._read_string()
            self._add(TT.STRING, s)
            return

        # Numbers (leading digit or negative sign followed by digit)
        if ch.isdigit() or (ch == "-" and self._peek(1) and self._peek(1).isdigit()):
            if ch == "-":
                self._advance()
                num = self._read_number()
                self._add(TT.NUMBER, -num)
            else:
                self._advance()
                self.pos -= 1  # rewind; _read_number starts from self.pos
                num = self._read_number()
                self._add(TT.NUMBER, num)
            return

        # Directives  @word
        if ch == "@":
            self._advance()
            word = self._read_word()
            if not word:
                raise LexError("bare '@' with no identifier", self.line)
            self._add(TT.DIRECTIVE, word)
            return

        # Identifiers / keywords
        if ch.isalpha() or ch == "_":
            word = self._read_word()
            if word == "true":
                self._add(TT.BOOL, True)
            elif word == "false":
                self._add(TT.BOOL, False)
            else:
                self._add(TT.IDENTIFIER, word)
            return

        # Single-character tokens
        single = {
            "[": TT.LBRACKET,
            "]": TT.RBRACKET,
            "{": TT.LBRACE,
            "}": TT.RBRACE,
            "|": TT.PIPE,
            ",": TT.COMMA,
            ":": TT.COLON,
        }
        if ch in single:
            self._advance()
            self._add(single[ch])
            return

        raise LexError(f"unexpected character {ch!r}", self.line)

"""
CFML Parser — converts a token stream into an AST.

Assignment direction is determined by the `left-to-right` header:
  true      → left token is value, right token is variable  (5 X  →  X = 5)
  false     → right token is value, left token is variable  (X 5  →  X = 5)
  arbitrary → heuristic: whichever side looks like a literal is the value
"""

from __future__ import annotations
from .lexer import Token, TT, Lexer, LexError
from .ast_nodes import (
    Node, ProgramNode, NumberNode, StringNode, BoolNode,
    IdentifierNode, ArrayNode, GroupSingleNode, GroupMultiNode,
    AssignNode, DirectiveNode, BlockDeclNode,
)


class ParseError(Exception):
    def __init__(self, msg: str, line: int):
        super().__init__(f"[line {line}] ParseError: {msg}")
        self.line = line


class Parser:
    def __init__(self, tokens: list[Token]):
        self.tokens = tokens
        self.pos = 0
        self.ltr: str = "true"   # set after header parse

    # ── Token navigation ──────────────────────────────────────────────────────

    def _peek(self, offset: int = 0) -> Token:
        idx = self.pos + offset
        return self.tokens[idx] if idx < len(self.tokens) else self.tokens[-1]

    def _advance(self) -> Token:
        tok = self.tokens[self.pos]
        if self.pos < len(self.tokens) - 1:
            self.pos += 1
        return tok

    def _check(self, *types: TT) -> bool:
        return self._peek().type in types

    def _match(self, *types: TT) -> Token | None:
        if self._check(*types):
            return self._advance()
        return None

    def _expect(self, tt: TT, msg: str = "") -> Token:
        if self._check(tt):
            return self._advance()
        tok = self._peek()
        raise ParseError(msg or f"expected {tt.name}, got {tok.type.name} ({tok.value!r})", tok.line)

    def _skip_newlines(self) -> None:
        while self._check(TT.NEWLINE):
            self._advance()

    # ── Public entry point ────────────────────────────────────────────────────

    def parse(self) -> ProgramNode:
        self._skip_newlines()
        version, ltr = self._parse_header()
        self.ltr = ltr
        self._skip_newlines()
        body = self._parse_body()
        return ProgramNode(version=version, left_to_right=ltr, body=body, line=1)

    # ── Header ────────────────────────────────────────────────────────────────

    def _parse_header(self) -> tuple[int, str]:
        version = 1
        ltr = "true"

        # `version N`
        if self._check(TT.IDENTIFIER) and self._peek().value == "version":
            self._advance()
            tok = self._expect(TT.NUMBER, "expected version number after 'version'")
            version = int(tok.value)
            if version != 1:
                raise ParseError(f"unsupported version {version}, only version 1 is defined", tok.line)
            self._match(TT.NEWLINE)

        # `left-to-right VALUE`
        if self._check(TT.IDENTIFIER) and self._peek().value == "left-to-right":
            self._advance()
            tok = self._peek()
            if tok.type == TT.BOOL:
                ltr = "true" if tok.value else "false"
                self._advance()
            elif tok.type == TT.IDENTIFIER and tok.value == "arbitrary":
                ltr = "arbitrary"
                self._advance()
            else:
                raise ParseError(
                    f"left-to-right expects true/false/arbitrary, got {tok.value!r}", tok.line
                )
            self._match(TT.NEWLINE)

        return version, ltr

    # ── Body ──────────────────────────────────────────────────────────────────

    def _parse_body(self) -> list[Node]:
        stmts: list[Node] = []
        while not self._check(TT.EOF):
            self._skip_newlines()
            if self._check(TT.EOF):
                break
            stmt = self._parse_statement()
            if stmt is not None:
                stmts.append(stmt)
        return stmts

    def _parse_statement(self) -> Node | None:
        tok = self._peek()

        if tok.type == TT.DIRECTIVE:
            return self._parse_directive_statement()

        if tok.type in (TT.NUMBER, TT.STRING, TT.BOOL, TT.IDENTIFIER):
            return self._parse_assignment_or_expr()

        # Unexpected — skip with a mildly annoyed message
        raise ParseError(
            f"unexpected token {tok.type.name} ({tok.value!r}) at start of statement", tok.line
        )

    # ── Assignment ────────────────────────────────────────────────────────────

    def _is_literal(self, tok: Token) -> bool:
        return tok.type in (TT.NUMBER, TT.STRING, TT.BOOL)

    def _parse_assignment_or_expr(self) -> Node:
        left_tok = self._advance()
        line = left_tok.line

        # Peek ahead — if there's a second value-like token on the same logical
        # line (before NEWLINE/EOF/DIRECTIVE), this is an assignment pair.
        right_tok = self._peek()
        if right_tok.type in (TT.NUMBER, TT.STRING, TT.BOOL, TT.IDENTIFIER) and \
                right_tok.line == line:
            self._advance()
            self._match(TT.NEWLINE)
            return self._make_assign(left_tok, right_tok)

        # Single token on a line — treat as a bare expression statement.
        # In practice this shouldn't appear in valid CFML but we handle it
        # gracefully so the REPL/debug dumps don't explode.
        self._match(TT.NEWLINE)
        return self._token_to_node(left_tok)

    def _make_assign(self, left: Token, right: Token) -> AssignNode:
        """Determine which token is the target variable and which is the value."""
        ltr = self.ltr

        if ltr == "true":
            # left = value, right = target
            value_tok, target_tok = left, right
        elif ltr == "false":
            # left = target, right = value
            target_tok, value_tok = left, right
        else:
            # arbitrary: whichever side is a literal is the value
            if self._is_literal(left) and not self._is_literal(right):
                value_tok, target_tok = left, right
            elif self._is_literal(right) and not self._is_literal(left):
                target_tok, value_tok = left, right
            elif self._is_literal(left) and self._is_literal(right):
                # Both literals — treat conventionally (left=value, right=target)
                value_tok, target_tok = left, right
            else:
                # Both identifiers — convention: left is value source, right is target
                value_tok, target_tok = left, right

        if target_tok.type != TT.IDENTIFIER:
            raise ParseError(
                f"assignment target must be an identifier, got {target_tok.type.name} ({target_tok.value!r})",
                target_tok.line,
            )

        return AssignNode(
            target=target_tok.value,
            value=self._token_to_node(value_tok),
            line=left.line,
        )

    def _token_to_node(self, tok: Token) -> Node:
        if tok.type == TT.NUMBER:
            return NumberNode(value=tok.value, line=tok.line)
        if tok.type == TT.STRING:
            return StringNode(value=tok.value, line=tok.line)
        if tok.type == TT.BOOL:
            return BoolNode(value=tok.value, line=tok.line)
        if tok.type == TT.IDENTIFIER:
            return IdentifierNode(name=tok.value, line=tok.line)
        raise ParseError(f"cannot convert token {tok.type.name} to node", tok.line)

    # ── Directives ────────────────────────────────────────────────────────────

    def _parse_directive_statement(self) -> Node:
        tok = self._advance()           # consume @name
        name = tok.value
        line = tok.line

        # @decl is special — it has a name, colon, and an indented body
        if name == "decl":
            return self._parse_block_decl(line)

        # Collect arguments until end-of-line
        args = self._parse_directive_args(line)
        self._match(TT.NEWLINE)
        return DirectiveNode(name=name, args=args, line=line)

    def _parse_directive_args(self, parent_line: int) -> list[Node]:
        """
        Parse zero or more argument expressions on the same line.
        Arguments can be: literals, identifiers, nested @directives,
        group expressions { }, multi-group | |, arrays [ ].
        """
        args: list[Node] = []
        while True:
            tok = self._peek()
            # Stop at end-of-line, EOF, or a colon (used in @decl)
            if tok.type in (TT.NEWLINE, TT.EOF):
                break
            if tok.type == TT.COLON:
                break
            node = self._parse_expr()
            args.append(node)
        return args

    def _parse_expr(self) -> Node:
        tok = self._peek()

        if tok.type in (TT.NUMBER, TT.STRING, TT.BOOL, TT.IDENTIFIER):
            self._advance()
            return self._token_to_node(tok)

        if tok.type == TT.DIRECTIVE:
            self._advance()
            args = self._parse_directive_args(tok.line)
            return DirectiveNode(name=tok.value, args=args, line=tok.line)

        if tok.type == TT.LBRACE:
            return self._parse_group_single()

        if tok.type == TT.PIPE:
            return self._parse_group_multi()

        if tok.type == TT.LBRACKET:
            return self._parse_array()

        raise ParseError(
            f"unexpected token in expression: {tok.type.name} ({tok.value!r})", tok.line
        )

    def _parse_group_single(self) -> GroupSingleNode:
        open_tok = self._expect(TT.LBRACE)
        expr = self._parse_expr()
        self._expect(TT.RBRACE, "expected '}' to close group")
        return GroupSingleNode(expr=expr, line=open_tok.line)

    def _parse_group_multi(self) -> GroupMultiNode:
        open_tok = self._expect(TT.PIPE)
        items: list[Node] = []
        while not self._check(TT.PIPE) and not self._check(TT.EOF):
            items.append(self._parse_expr())
        self._expect(TT.PIPE, "expected '|' to close multi-group")
        return GroupMultiNode(items=items, line=open_tok.line)

    def _parse_array(self) -> ArrayNode:
        open_tok = self._expect(TT.LBRACKET)
        elements: list[Node] = []
        while not self._check(TT.RBRACKET) and not self._check(TT.EOF):
            elements.append(self._parse_expr())
            self._match(TT.COMMA)
        self._expect(TT.RBRACKET, "expected ']' to close array")
        return ArrayNode(elements=elements, line=open_tok.line)

    # ── Block declaration ─────────────────────────────────────────────────────

    def _parse_block_decl(self, line: int) -> BlockDeclNode:
        """
        @decl name:
        --statement
        --statement
        """
        name_tok = self._expect(TT.IDENTIFIER, "expected block name after @decl")
        self._expect(TT.COLON, "expected ':' after block name in @decl")
        self._match(TT.NEWLINE)

        body: list[Node] = []
        while self._check(TT.INDENT):
            self._advance()  # consume --
            stmt = self._parse_statement()
            if stmt is not None:
                body.append(stmt)
            self._match(TT.NEWLINE)

        return BlockDeclNode(block_name=name_tok.value, body=body, line=line)


# ── Convenience function ──────────────────────────────────────────────────────

def parse_source(source: str) -> ProgramNode:
    tokens = Lexer(source).tokenize()
    return Parser(tokens).parse()

"""
Core directive implementations for the CFML interpreter.
Each function receives (interpreter, args_nodes, line) and returns a value or None.
"""

from __future__ import annotations
from typing import TYPE_CHECKING

if TYPE_CHECKING:
    from ..interpreter import Interpreter
    from ..ast_nodes import Node


# ── Type conversion helpers ───────────────────────────────────────────────────

def _to_int(v: object, line: int) -> int:
    try:
        if isinstance(v, float):
            return int(v)
        if isinstance(v, str):
            return int(float(v))
        if isinstance(v, bool):
            return int(v)
        return int(v)
    except (ValueError, TypeError):
        raise RuntimeError(f"[line {line}] cannot convert {v!r} to int")


def _to_float(v: object, line: int) -> float:
    try:
        return float(v)
    except (ValueError, TypeError):
        raise RuntimeError(f"[line {line}] cannot convert {v!r} to float")


def _to_bool(v: object, line: int) -> bool:
    if isinstance(v, bool):
        return v
    if isinstance(v, (int, float)):
        return v != 0
    if isinstance(v, str):
        if v.lower() in ("true", "1"):
            return True
        if v.lower() in ("false", "0", ""):
            return False
        raise RuntimeError(f"[line {line}] cannot convert string {v!r} to bool")
    raise RuntimeError(f"[line {line}] cannot convert {type(v).__name__} to bool")


def _to_string(v: object, line: int) -> str:
    if isinstance(v, bool):
        return "true" if v else "false"
    return str(v)


_CONVERTERS = {
    "int": _to_int,
    "float": _to_float,
    "bool": _to_bool,
    "string": _to_string,
}


# ── Deep equality ─────────────────────────────────────────────────────────────

def _cfml_eq(a: object, b: object) -> bool:
    """Strict CFML equality: same type, same value. Recursive for lists."""
    if type(a) is not type(b):
        return False
    if isinstance(a, list):
        if len(a) != len(b):
            return False
        return all(_cfml_eq(x, y) for x, y in zip(a, b))
    return a == b


# ── Directive handlers ────────────────────────────────────────────────────────

def directive_log(interp: "Interpreter", args: list["Node"], line: int) -> None:
    if not args:
        raise RuntimeError(f"[line {line}] @log requires at least one argument")
    for arg in args:
        val = interp.eval(arg)
        print(_to_string(val, line))


def directive_get(interp: "Interpreter", args: list["Node"], line: int) -> None:
    if len(args) != 1:
        raise RuntimeError(f"[line {line}] @get requires exactly one argument (variable name)")
    from ..ast_nodes import IdentifierNode
    arg = args[0]
    if not isinstance(arg, IdentifierNode):
        raise RuntimeError(f"[line {line}] @get argument must be an identifier")
    raw = input()
    interp.env[arg.name] = raw


def directive_eq(interp: "Interpreter", args: list["Node"], line: int) -> bool:
    if len(args) != 2:
        raise RuntimeError(f"[line {line}] @eq requires exactly two arguments")
    a = interp.eval(args[0])
    b = interp.eval(args[1])
    return _cfml_eq(a, b)


def directive_neg(interp: "Interpreter", args: list["Node"], line: int) -> bool:
    if len(args) != 1:
        raise RuntimeError(f"[line {line}] @neg requires exactly one argument")
    val = interp.eval(args[0])
    if not isinstance(val, bool):
        raise RuntimeError(f"[line {line}] @neg requires a boolean, got {type(val).__name__}")
    return not val


def directive_conv(interp: "Interpreter", args: list["Node"], line: int) -> None:
    """@conv SOURCE TYPE TARGET"""
    if len(args) != 3:
        raise RuntimeError(f"[line {line}] @conv requires exactly three arguments: source type target")
    from ..ast_nodes import IdentifierNode, StringNode
    source_val = interp.eval(args[0])

    type_node = args[1]
    if isinstance(type_node, IdentifierNode):
        type_name = type_node.name
    elif isinstance(type_node, StringNode):
        type_name = type_node.value
    else:
        raise RuntimeError(f"[line {line}] @conv type argument must be an identifier (int/float/bool/string)")

    if type_name not in _CONVERTERS:
        raise RuntimeError(f"[line {line}] unknown type '{type_name}', expected: {', '.join(_CONVERTERS)}")

    target = args[2]
    if not isinstance(target, IdentifierNode):
        raise RuntimeError(f"[line {line}] @conv target must be an identifier")

    converted = _CONVERTERS[type_name](source_val, line)
    interp.env[target.name] = converted


def directive_jmp(interp: "Interpreter", args: list["Node"], line: int) -> None:
    if len(args) != 1:
        raise RuntimeError(f"[line {line}] @jmp requires exactly one argument (block name)")
    from ..ast_nodes import IdentifierNode
    arg = args[0]
    if not isinstance(arg, IdentifierNode):
        raise RuntimeError(f"[line {line}] @jmp argument must be a block name identifier")
    block_name = arg.name
    if block_name not in interp.blocks:
        raise RuntimeError(f"[line {line}] undefined block '{block_name}'")
    block = interp.blocks[block_name]
    for stmt in block.body:
        interp.exec(stmt)


def directive_turing(interp: "Interpreter", args: list["Node"], line: int) -> bool:
    return True


def directive_reverse(interp: "Interpreter", args: list["Node"], line: int) -> None:
    interp.reverse_mode = True


# ── Registry ──────────────────────────────────────────────────────────────────

CORE_DIRECTIVES: dict[str, callable] = {
    "log":     directive_log,
    "get":     directive_get,
    "eq":      directive_eq,
    "neg":     directive_neg,
    "conv":    directive_conv,
    "jmp":     directive_jmp,
    "turing":  directive_turing,
    "reverse": directive_reverse,
}

"""
CFML Interpreter — tree-walking executor.
"""

from __future__ import annotations
from .ast_nodes import (
    Node, ProgramNode, NumberNode, StringNode, BoolNode,
    IdentifierNode, ArrayNode, GroupSingleNode, GroupMultiNode,
    AssignNode, DirectiveNode, BlockDeclNode,
)
from .directives.core import CORE_DIRECTIVES


class CFMLRuntimeError(Exception):
    pass


class Interpreter:
    def __init__(self):
        self.env: dict[str, object] = {}
        self.blocks: dict[str, BlockDeclNode] = {}
        self.reverse_mode: bool = False

    # ── Public entry point ────────────────────────────────────────────────────

    def run(self, program: ProgramNode) -> None:
        # First pass: register all block declarations so forward @jmp works
        for stmt in program.body:
            if isinstance(stmt, BlockDeclNode):
                self.blocks[stmt.block_name] = stmt

        stmts = program.body
        if self.reverse_mode or self._has_reverse(stmts):
            # @reverse encountered during pre-scan? Execute bottom-to-top.
            # We do a real pre-scan here so @reverse in the middle of a file
            # affects the whole program's execution order.
            pass

        # Determine execution order: check if @reverse directive appears anywhere
        order = list(reversed(stmts)) if self._has_reverse_directive(stmts) else stmts

        for stmt in order:
            self.exec(stmt)
            if self.reverse_mode:
                # @reverse was hit at runtime — re-run remaining stmts reversed
                # This handles @reverse mid-program correctly.
                break

    def _has_reverse(self, stmts: list[Node]) -> bool:
        return self._has_reverse_directive(stmts)

    def _has_reverse_directive(self, stmts: list[Node]) -> bool:
        for stmt in stmts:
            if isinstance(stmt, DirectiveNode) and stmt.name == "reverse":
                return True
        return False

    # ── Statement execution ───────────────────────────────────────────────────

    def exec(self, node: Node) -> None:
        if isinstance(node, BlockDeclNode):
            self.blocks[node.block_name] = node
            return

        if isinstance(node, AssignNode):
            self.env[node.target] = self.eval(node.value)
            return

        if isinstance(node, DirectiveNode):
            self.eval_directive(node)
            return

        # Bare expressions (shouldn't normally appear at statement level
        # but we evaluate them for their side effects anyway)
        self.eval(node)

    # ── Expression evaluation ─────────────────────────────────────────────────

    def eval(self, node: Node) -> object:
        if isinstance(node, NumberNode):
            return node.value

        if isinstance(node, StringNode):
            return node.value

        if isinstance(node, BoolNode):
            return node.value

        if isinstance(node, IdentifierNode):
            if node.name not in self.env:
                raise CFMLRuntimeError(
                    f"[line {node.line}] undefined variable '{node.name}'"
                )
            return self.env[node.name]

        if isinstance(node, ArrayNode):
            return [self.eval(e) for e in node.elements]

        if isinstance(node, GroupSingleNode):
            return self.eval(node.expr)

        if isinstance(node, GroupMultiNode):
            return [self.eval(item) for item in node.items]

        if isinstance(node, DirectiveNode):
            return self.eval_directive(node)

        raise CFMLRuntimeError(
            f"[line {node.line}] cannot evaluate node type {type(node).__name__}"
        )

    # ── Directive dispatch ────────────────────────────────────────────────────

    def eval_directive(self, node: DirectiveNode) -> object:
        name = node.name

        # @decl at expression level is a no-op (already registered)
        if name == "decl":
            return None

        handler = CORE_DIRECTIVES.get(name)
        if handler is None:
            # Check meme / dangerous directives lazily to keep imports clean
            handler = self._load_extended_directive(name, node.line)

        return handler(self, node.args, node.line)

    def _load_extended_directive(self, name: str, line: int):
        # Meme directives (Milestone 6) — not yet implemented
        meme_stubs = {"nyancat", "gordonramsay"}
        dangerous_stubs = {"nuke", "cryptoscam"}

        if name in meme_stubs:
            raise CFMLRuntimeError(
                f"[line {line}] @{name} is a meme directive — coming in Milestone 6"
            )
        if name in dangerous_stubs:
            raise CFMLRuntimeError(
                f"[line {line}] @{name} is a dangerous directive — coming in Milestone 7 (requires --dangerous flag)"
            )

        raise CFMLRuntimeError(
            f"[line {line}] unknown directive '@{name}'"
        )

